// PDF generation
const generatePDFFromHTML = async (document, type) => {
  const isQuote = type === 'quote';
  const number = isQuote ? document.quote_number : document.invoice_number;
  const prefix = isQuote ? 'DEVIS' : 'FACTURE';
  const filename = `${prefix}_${number || 'XX'}_${(document.client_name || 'client').replace(/\s+/g, '_')}.pdf`;

  const container = window.document.createElement('div');
  container.style.cssText = 'position:fixed;top:0;left:-9999px;width:794px;background:white;z-index:-9999;pointer-events:none;';
  window.document.body.appendChild(container);
  const root = createRoot(container);
  root.render(<PDFDocument document={document} type={type} compact={false} />);

  try {
    await new Promise(r => setTimeout(r, 1000));
    await window.document.fonts.ready;
    const canvas = await html2canvas(container.firstChild, {
      scale: 2.5, useCORS: true, allowTaint: false, backgroundColor: '#ffffff', logging: false,
      onclone: (clonedDoc) => {
        clonedDoc.querySelectorAll('img').forEach(img => {
          const b64 = LOGO_B64_MAP[img.src] || LOGO_B64_MAP[img.getAttribute('src')];
          if (b64) img.src = b64;
        });
      },
    });
    const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
    const pageW = pdf.internal.pageSize.getWidth();
    const pageH = pdf.internal.pageSize.getHeight();
    const pxPerMm = canvas.width / pageW;
    const pageHpx = pageH * pxPerMm;
    const totalPages = Math.ceil(canvas.height / pageHpx);
    for (let p = 0; p < totalPages; p++) {
      if (p > 0) pdf.addPage();
      const sc = window.document.createElement('canvas');
      sc.width = canvas.width;
      const start = p * pageHpx;
      sc.height = Math.ceil(Math.min(pageHpx, canvas.height - start));
      sc.getContext('2d').drawImage(canvas, 0, -start);
      pdf.addImage(sc.toDataURL('image/jpeg', 0.95), 'JPEG', 0, 0, pageW, (sc.height / canvas.width) * pageW);
    }
    pdf.save(filename);
    return true;
  } finally {
    root.unmount();
    window.document.body.removeChild(container);
  }
};

const generatePDFBase64 = async (document, type) => {
  const isQuote = type === 'quote';
  const number = isQuote ? document.quote_number : document.invoice_number;
  const prefix = isQuote ? 'Devis_SR-Renovation' : 'Facture_SR-Renovation';
  const filename = `${prefix}_${number || 'XX'}.pdf`;

  const container = window.document.createElement('div');
  container.style.cssText = 'position:fixed;top:0;left:-9999px;width:794px;background:white;z-index:-9999;pointer-events:none;';
  window.document.body.appendChild(container);
  const root = createRoot(container);
  root.render(<PDFDocument document={document} type={type} compact={false} />);

  try {
    // Attendre le rendu et les images
    await new Promise(r => setTimeout(r, 2000));
    await window.document.fonts.ready;
    
    // Pré-charger toutes les images en base64
    const images = container.querySelectorAll('img');
    await Promise.all(Array.from(images).map(img => {
      return new Promise((resolve) => {
        if (img.complete) {
          resolve();
        } else {
          img.onload = () => resolve();
          img.onerror = () => resolve();
        }
      });
    }));
    
    const canvas = await html2canvas(container.firstChild, {
      scale: 2.5, useCORS: true, allowTaint: false, backgroundColor: '#ffffff', logging: false,
      onclone: (clonedDoc) => {
        clonedDoc.querySelectorAll('img').forEach(img => {
          const b64 = LOGO_B64_MAP[img.src] || LOGO_B64_MAP[img.getAttribute('src')];
          if (b64) img.src = b64;
        });
      },
    });
    const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
    const pageW = pdf.internal.pageSize.getWidth();
    const pageH = pdf.internal.pageSize.getHeight();
    const pxPerMm = canvas.width / pageW;
    const pageHpx = pageH * pxPerMm;
    const totalPages = Math.ceil(canvas.height / pageHpx);
    for (let p = 0; p < totalPages; p++) {
      if (p > 0) pdf.addPage();
      const sc = window.document.createElement('canvas');
      sc.width = canvas.width;
      const start = p * pageHpx;
      sc.height = Math.ceil(Math.min(pageHpx, canvas.height - start));
      sc.getContext('2d').drawImage(canvas, 0, -start);
      pdf.addImage(sc.toDataURL('image/jpeg', 0.95), 'JPEG', 0, 0, pageW, (sc.height / canvas.width) * pageW);
    }
    const base64 = pdf.output('datauristring').split(',')[1];
    return { base64, filename };
  } finally {
    root.unmount();
    window.document.body.removeChild(container);
  }
};

const downloadPDF = async (document, type) => {
  try {
    await generatePDFFromHTML(document, type);
    toast.success('PDF téléchargé avec succès');
    return true;
  } catch (err) {
    console.error('PDF error:', err);
    toast.error('Erreur lors de la génération du PDF');
    return false;
  }
};

const PDFPreview = ({ document, type, onClose }) => {
  if (!document) return null;
  return (
    <div className="fixed inset-0 bg-black/60 z-50 flex items-start justify-center p-4 pt-8 backdrop-blur-sm overflow-y-auto" data-testid="pdf-preview-modal">
      <div className="bg-white rounded-xl max-w-4xl w-full shadow-2xl relative">
        <div className="sticky top-0 z-10 bg-white border-b border-gray-200 px-4 py-3 flex items-center justify-between rounded-t-xl">
          <h2 className="font-semibold text-gray-900" data-testid="preview-title">Aperçu {type === 'quote' ? 'Devis' : 'Facture'}</h2>
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm" onClick={() => downloadPDF(document, type)} style={{ borderColor: BRAND_BLUE, color: BRAND_BLUE }} data-testid="download-pdf-btn">
              <Download className="h-4 w-4 mr-1.5" /> Télécharger PDF
            </Button>
            <Button variant="ghost" size="sm" onClick={onClose} data-testid="close-preview-btn"><X className="h-5 w-5" /></Button>
          </div>
        </div>
        <div className="p-4 bg-gray-100">
          <div className="mx-auto shadow-lg rounded overflow-hidden" style={{ maxWidth: '210mm' }}>
            <PDFDocument document={document} type={type} />
          </div>
        </div>
      </div>
    </div>
  );
};

export { PDFDocument, downloadPDF, generatePDFFromHTML, generatePDFBase64, BRAND_BLUE, BRAND_ORANGE };
export default PDFPreview;
